/**
 * Generate role test data based on pattern
 *
 * @param pattern - The test data pattern to generate
 * @param overrides - Optional field overrides
 * @returns Generated test data
 *
 * @example
 * ```typescript
 * // Generate complete test data
 * const data = generateRoleTestData('complete');
 *
 * // Generate unique test data with overrides
 * const customData = generateRoleTestData('unique', {
 *   is_active: false,
 * });
 * ```
 */
export function generateRoleTestData(
  pattern: TestDataPattern = 'complete',
  overrides: Partial<RoleCreateRequest> = {}
): RoleCreateRequest {
  let baseData: RoleCreateRequest;

  switch (pattern) {
    case 'minimal':
      baseData = { ...minimalRoleFixture };
      break;

    case 'complete':
      baseData = { ...completeRoleFixture };
      break;

    case 'invalid':
      // Return invalid data (caller should handle validation failure)
      baseData = { ...invalidRoleFixture } as RoleCreateRequest;
      break;

    case 'unique':
      // Generate fresh unique values for each call
      baseData = {
        ...uniqueRoleFixture,
        name: `Test Role ${generateUniqueId()}`,
        code: `TST-${generateUniqueId()}`.substring(0, 20),
      };
      break;

    default:
      baseData = { ...completeRoleFixture };
  }

  return { ...baseData, ...overrides };
}

/**
 * Generate multiple role fixtures
 *
 * @param count - Number of fixtures to generate
 * @param pattern - The test data pattern to use as base
 * @param modifier - Optional function to modify each fixture
 * @returns Array of generated test data
 *
 * @example
 * ```typescript
 * // Generate 5 unique fixtures
 * const fixtures = generateMultipleRoleFixtures(5, 'unique');
 *
 * // Generate fixtures with sequential numbering
 * const numbered = generateMultipleRoleFixtures(3, 'complete', (data, index) => ({
 *   ...data,
 *   name: `Role #${index + 1}`,
 * }));
 * ```
 */
export function generateMultipleRoleFixtures(
  count: number,
  pattern: TestDataPattern = 'unique',
  modifier?: (data: RoleCreateRequest, index: number) => RoleCreateRequest
): RoleCreateRequest[] {
  const fixtures: RoleCreateRequest[] = [];

  for (let i = 0; i < count; i++) {
    let fixture = generateRoleTestData(pattern);

    if (modifier) {
      fixture = modifier(fixture, i);
    } else if (pattern === 'unique') {
      // Add index to ensure uniqueness even with same timestamp
      fixture.name = `Test Role ${generateUniqueId()}-${i}`;
      fixture.code = `TST-${i}-${generateUniqueId()}`.substring(0, 20);
    }

    fixtures.push(fixture);
  }

  return fixtures;
}

